import React from 'react';

const certifications = [
  {
    title: 'AWS Cloud Practitioner',
    issuer: 'Amazon Web Services',
    year: '2023',
    accent: '#FF9900',
    icon: '☁️',
    badge: 'AWS',
  },
  {
    title: 'Azure Fundamentals AZ-900',
    issuer: 'Microsoft',
    year: '2023',
    accent: '#0078d4',
    icon: '🔷',
    badge: 'AZ-900',
  },
  {
    title: 'Certified in Cybersecurity (CC)',
    issuer: 'ISC2',
    year: '2023',
    accent: '#c23b22',
    icon: '🔒',
    badge: 'CC',
  },
  {
    title: 'Technical Security Audit & Assessment',
    issuer: 'LinkedIn Learning',
    year: '2023',
    accent: '#0a66c2',
    icon: '🛡️',
    badge: 'LI',
  },
  {
    title: 'PowerShell: Automating IT Administration',
    issuer: 'LinkedIn Learning',
    year: '2023',
    accent: '#0a66c2',
    icon: '⚙️',
    badge: 'LI',
  },
  {
    title: 'Cybersecurity with Cloud Computing',
    issuer: 'LinkedIn Learning',
    year: '2022',
    accent: '#0a66c2',
    icon: '🔐',
    badge: 'LI',
  },
];

const AzureIcon: React.FC = () => (
  <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 96 96" width="36" height="36">
    <defs>
      <linearGradient id="az-grad-1" x1="-1032.172" y1="145.312" x2="-1059.213" y2="65.426" gradientTransform="matrix(1 0 0 -1 1075 158)" gradientUnits="userSpaceOnUse">
        <stop offset="0" stopColor="#114a8b"/>
        <stop offset="1" stopColor="#0669bc"/>
      </linearGradient>
      <linearGradient id="az-grad-2" x1="-1023.725" y1="108.083" x2="-1029.98" y2="105.968" gradientTransform="matrix(1 0 0 -1 1075 158)" gradientUnits="userSpaceOnUse">
        <stop offset="0" stopOpacity=".3"/>
        <stop offset=".071" stopOpacity=".2"/>
        <stop offset=".321" stopOpacity=".1"/>
        <stop offset=".623" stopOpacity=".05"/>
        <stop offset="1" stopOpacity="0"/>
      </linearGradient>
      <linearGradient id="az-grad-3" x1="-1027.165" y1="147.642" x2="-997.482" y2="68.561" gradientTransform="matrix(1 0 0 -1 1075 158)" gradientUnits="userSpaceOnUse">
        <stop offset="0" stopColor="#3ccbf4"/>
        <stop offset="1" stopColor="#2892df"/>
      </linearGradient>
    </defs>
    <path d="M33.338 6.544h26.038l-27.03 80.087a4.152 4.152 0 0 1-3.933 2.824H8.149a4.145 4.145 0 0 1-3.928-5.47L29.404 9.368a4.152 4.152 0 0 1 3.934-2.824z" fill="url(#az-grad-1)"/>
    <path d="M71.175 60.261H33.376a1.91 1.91 0 0 0-1.305 3.308l24.267 22.679a4.171 4.171 0 0 0 2.838 1.107h21.44z" fill="#1f9cf0"/>
    <path d="M33.338 6.544a4.118 4.118 0 0 0-3.943 2.879L4.252 83.917a4.14 4.14 0 0 0 3.908 5.538h20.787a4.443 4.443 0 0 0 3.41-2.9l5.014-14.777 17.91 16.705a4.237 4.237 0 0 0 2.666.934h23.254l-10.224-29.134-29.781.007L51.369 6.544z" fill="url(#az-grad-2)"/>
    <path d="M66.595 9.368a4.145 4.145 0 0 0-3.928-2.824H33.648a4.146 4.146 0 0 1 3.928 2.824l25.184 74.62a4.146 4.146 0 0 1-3.928 5.467h29.02a4.146 4.146 0 0 0 3.927-5.467z" fill="url(#az-grad-3)"/>
  </svg>
);

const ongoingCertifications = [
  {
    title: 'Azure Administrator Associate AZ-104',
    issuer: 'Microsoft',
    year: '2024',
    accent: '#0078d4',
    icon: null as null,
    badge: 'AZ-104',
    azureIcon: true,
  },
];

const SectionTitle: React.FC<{ title: string; count?: string }> = ({ title, count }) => (
  <div style={{ marginBottom: 16 }}>
    <div style={{ display: 'flex', alignItems: 'baseline', gap: 10 }}>
      <h3 style={{ fontSize: 15, fontWeight: 'bold', color: '#000080' }}>{title}</h3>
      {count && <span style={{ fontSize: 10, color: '#999', letterSpacing: 1 }}>{count}</span>}
    </div>
    <div style={{ height: 2, background: 'linear-gradient(90deg, #000080 0%, #e0e0e0 100%)', marginTop: 4 }} />
  </div>
);

type Cert = typeof certifications[0];
type OngoingCert = typeof ongoingCertifications[0];

const CertRow: React.FC<{ cert: Cert | OngoingCert; ongoing?: boolean }> = ({ cert, ongoing }) => (
  <div style={{
    display: 'flex', alignItems: 'center',
    border: `1px solid ${ongoing ? '#e8a000' : '#e8e8e8'}`, overflow: 'hidden',
  }}>
    <div style={{
      width: 72, flexShrink: 0,
      background: ongoing ? '#b8860b' : cert.accent,
      padding: '14px 0',
      display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', gap: 4,
    }}>
      {'azureIcon' in cert && cert.azureIcon ? <AzureIcon /> : <span style={{ fontSize: 20 }}>{cert.icon}</span>}
      <span style={{ fontSize: 9, fontWeight: 'bold', color: '#fff', letterSpacing: 1 }}>{cert.badge}</span>
    </div>
    <div style={{ flex: 1, padding: '12px 16px', background: ongoing ? '#fffbf0' : '#fafafa' }}>
      <div style={{ fontSize: 12, fontWeight: 'bold', color: '#222', marginBottom: 3 }}>{cert.title}</div>
      <div style={{ fontSize: 11, color: '#555' }}>{cert.issuer}</div>
    </div>
    <div style={{
      width: ongoing ? 80 : 60, flexShrink: 0,
      display: 'flex', alignItems: 'center', justifyContent: 'center',
      background: ongoing ? '#fff8e0' : '#f0f0f0',
      borderLeft: `1px solid ${ongoing ? '#e8c96a' : '#e8e8e8'}`, alignSelf: 'stretch',
    }}>
      {ongoing
        ? <span style={{ fontSize: 9, color: '#9a6a00', fontWeight: 'bold', textAlign: 'center', lineHeight: 1.3 }}>IN{'\n'}PROGRESS</span>
        : <span style={{ fontSize: 11, color: '#777', fontWeight: 'bold' }}>{cert.year}</span>
      }
    </div>
  </div>
);

const Certifications: React.FC = () => (
  <div style={{ padding: '28px 32px', overflowY: 'auto', background: '#fff' }}>
    <SectionTitle title="Certifications" count={`${certifications.length} CERTIFICATIONS`} />
    <div style={{ display: 'flex', flexDirection: 'column', gap: 10, marginBottom: 36 }}>
      {certifications.map((cert) => (
        <CertRow key={cert.title} cert={cert} />
      ))}
    </div>

    <SectionTitle title="Ongoing Learning" count={`${ongoingCertifications.length} IN PROGRESS`} />
    <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
      {ongoingCertifications.map((cert) => (
        <CertRow key={cert.title} cert={cert} ongoing />
      ))}
    </div>
  </div>
);

export default Certifications;
